#include <bits/stdc++.h>
#define x first
#define y second
using namespace std;

const int N=5e5+10,mod=1e9+7,inv6=166666668;
//inv6 为 1/6 的逆元

int n,m,k,ans;
pair<int,int> ob[N];

/*
int quick_mi(int a,int b){
    long long ans=1,base=a;
    while(b){
        if(b&1)
            ans=ans*base%mod;
        base=base*base%mod,b>>=1;
    }
    return ans;
}
*/

bool cmp(pair<int,int> a,pair<int,int> b){
    return a.y<b.y;
}

int main(){
    scanf("%d%d%d",&n,&m,&k);
    for(int i=1;i<=k;i++)
        scanf("%d%d",&ob[i].x,&ob[i].y);
    ans=(1LL*m*m%mod*n%mod*(n+1)%mod*(n-1)%mod+1LL*n*n%mod*m%mod*(m+1)%mod*(m-1)%mod)*inv6%mod;
    //printf("%d\n",ans);
    sort(ob+1,ob+k+1);
    int sumx=0;
    for(int i=1;i<=k;i++){
        ans=(ans-(1LL*(ob[i].x-1)*ob[i].x/2+1LL*(n-ob[i].x)*(n-ob[i].x+1)/2)%mod*m%mod)%mod;
        //printf("-%d\n",(1LL*(ob[i].x-1)*ob[i].x/2+1LL*(n-ob[i].x)*(n-ob[i].x+1)/2)%mod*m%mod);
        sumx=(sumx+ob[i].x)%mod;
        ans=(ans+1LL*i*ob[i].x-sumx)%mod;
    }
    sort(ob+1,ob+k+1,cmp);
    int sumy=0;
    for(int i=1;i<=k;i++){
        ans=(ans-(1LL*(ob[i].y-1)*ob[i].y/2+1LL*(m-ob[i].y)*(m-ob[i].y+1)/2)%mod*n%mod)%mod;
        //printf("-%d\n",(1LL*(ob[i].y-1)*ob[i].y/2+1LL*(m-ob[i].y)*(m-ob[i].y+1)/2)%mod*n%mod);
        sumy=(sumy+ob[i].y)%mod;
        ans=(ans+1LL*i*ob[i].y-sumy)%mod;
    }
    printf("%d",(ans+mod)%mod);
    return 0;
}
